class Solution {
    public long validSubstringCount(String word1, String word2) {
        int[] count = new int[26];
        int word2Len = word2.length();
        long countValid = 0;
        for (int i = 0; i < word1.length(); i++) {
            count[word1.charAt(i) - 'a']++;
            int j = 0;
            while (j < word2Len && count[word2.charAt(j) - 'a'] >= 1) {
                count[word2.charAt(j) - 'a']--;
                j++;
            }
            if (j == word2Len) {
                countValid += word1.length() - i;
            }
        }
        return countValid;
    }
}
